INSERT INTO recipes (id, title, summary, cover_image, age_label, age_min_months, age_max_months, duration_label, difficulty_label, source, creator, favorites, review_focus, content_status, review_status) VALUES
('recipe-096', '番茄牛肉软饭', '牛肉富含铁锌，番茄提供维生素C促进铁吸收，搭配软饭，营养均衡，是12月龄后的理想主食。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '40分钟', '中级', '营养师精品', '陈营养师', 435, '铁锌双补主食', 'published', 'approved'),
('recipe-097', '三色蔬菜炒蛋', '胡萝卜、玉米、豌豆三色蔬菜搭配鸡蛋，颜色鲜艳，营养全面，锻炼宝宝对固体食物的接受。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '18分钟', '初级', '营养师精品', '陈营养师', 360, '三色营养炒蛋', 'published', 'approved'),
('recipe-098', '鸡肉蔬菜饺子', '手工小饺子，鸡肉蔬菜馅料，皮薄馅嫩，是宝宝学习自主进食的好手指食物。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '35分钟', '高级', '营养师精品', '陈营养师', 275, '手指食物自主进食', 'published', 'approved'),
('recipe-099', '南瓜鸡肉焖饭', '南瓜与鸡肉同焖，米饭吸收了南瓜的甜味和鸡肉的鲜味，颜色金黄，香气诱人。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '35分钟', '中级', '营养师精品', '陈营养师', 385, '金黄焖饭香气诱人', 'published', 'approved'),
('recipe-100', '西兰花虾仁炒饭', '虾仁富含蛋白质和锌，西兰花提供维生素C，搭配软米饭，是宝宝营养炒饭的好选择。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '25分钟', '中级', '营养师精品', '陈营养师', 225, '补锌营养炒饭', 'published', 'approved'),
('recipe-101', '猪肉白菜包子', '软糯的包子皮包裹猪肉白菜馅，是宝宝学习咀嚼的好练习，也是家庭早餐的好选择。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '50分钟', '高级', '营养师精品', '陈营养师', 185, '咀嚼练习包子', 'published', 'approved'),
('recipe-102', '番茄鸡蛋面', '经典番茄鸡蛋面，酸甜开胃，面条软烂，是宝宝最爱的面食之一，简单快手。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '20分钟', '初级', '营养师精品', '陈营养师', 460, '经典酸甜面食', 'published', 'approved'),
('recipe-103', '三文鱼炒饭', '三文鱼碎与米饭同炒，DHA丰富，加入少量蔬菜，营养均衡，是宝宝补脑的美味主食。', 'https://images.unsplash.com/photo-1467003909585-2f8a72700288?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '20分钟', '中级', '营养师精品', '陈营养师', 372, 'DHA补脑炒饭', 'published', 'approved'),
('recipe-104', '豆腐蔬菜煎饼', '豆腐与蔬菜混合煎制，外酥内嫩，是宝宝手指食物的好选择，植物蛋白丰富。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '25分钟', '中级', '营养师精品', '陈营养师', 205, '外酥内嫩手指食物', 'published', 'approved'),
('recipe-105', '香菇猪肉粥', '香菇的鲜味与猪肉的醇香融合，搭配软烂大米，是宝宝冬季暖胃的营养粥品。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '40分钟', '中级', '营养师精品', '陈营养师', 192, '冬季暖胃鲜味粥', 'published', 'approved')
INSERT INTO recipes (id, title, summary, cover_image, age_label, age_min_months, age_max_months, duration_label, difficulty_label, source, creator, favorites, review_focus, content_status, review_status) VALUES
('recipe-106', '胡萝卜牛肉软饭', '牛肉末与胡萝卜丁搭配软饭，铁质丰富，颜色橙黄，营养均衡，是宝宝午餐的好选择。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '35分钟', '中级', '营养师精品', '陈营养师', 175, '铁质丰富午餐', 'published', 'approved'),
('recipe-107', '鸡蛋蔬菜煎饼', '鸡蛋与多种蔬菜混合煎制，外酥内嫩，营养丰富，是宝宝早餐或加餐的好选择。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '18分钟', '初级', '营养师精品', '陈营养师', 340, '早餐营养煎饼', 'published', 'approved'),
('recipe-108', '虾仁豆腐羹', '虾仁与豆腐同煮，蛋白质丰富，口感嫩滑，加入少量淀粉勾芡，更适合宝宝食用。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '20分钟', '中级', '营养师精品', '陈营养师', 165, '嫩滑双蛋白羹', 'published', 'approved'),
('recipe-109', '南瓜小米饭', '南瓜与小米同煮，颜色金黄，养胃健脾，是宝宝秋冬季节的暖胃主食。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '30分钟', '初级', '营养师精品', '陈营养师', 150, '养胃健脾金黄饭', 'published', 'approved'),
('recipe-110', '猪肝菠菜面', '猪肝与菠菜的铁质双补，搭配细软面条，是宝宝补铁的营养面食，每周1-2次。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '25分钟', '中级', '营养师精品', '陈营养师', 162, '铁质双补面食', 'published', 'approved'),
('recipe-111', '鳕鱼豆腐汤', '鳕鱼与豆腐同煮，汤色乳白，DHA与植物蛋白双补，口感鲜嫩，宝宝超爱喝。', 'https://images.unsplash.com/photo-1467003909585-2f8a72700288?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '23分钟', '初级', '营养师精品', '陈营养师', 352, 'DHA乳白鲜汤', 'published', 'approved'),
('recipe-112', '西红柿牛肉面', '牛肉的鲜味与西红柿的酸甜完美融合，面条软烂，是宝宝最爱的营养面食之一。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '30分钟', '中级', '营养师精品', '陈营养师', 425, '酸甜牛肉面', 'published', 'approved'),
('recipe-113', '香菇蒸蛋', '香菇切碎与鸡蛋同蒸，鲜味十足，口感嫩滑，是宝宝补充B族维生素的好选择。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '17分钟', '初级', '营养师精品', '陈营养师', 182, '鲜味嫩滑蒸蛋', 'published', 'approved'),
('recipe-114', '鸡肉蔬菜炒饭', '鸡肉末与多种蔬菜搭配炒饭，颜色丰富，营养全面，是宝宝学习自主进食的好选择。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '25分钟', '中级', '营养师精品', '陈营养师', 205, '多彩营养炒饭', 'published', 'approved'),
('recipe-115', '红薯燕麦粥', '红薯的甜味与燕麦的营养结合，富含膳食纤维，是宝宝早餐的好选择，有助于肠道健康。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '20分钟', '初级', '手机快速添加', '运营-小顾', 162, '肠道健康早餐粥', 'published', 'approved')
INSERT INTO recipes (id, title, summary, cover_image, age_label, age_min_months, age_max_months, duration_label, difficulty_label, source, creator, favorites, review_focus, content_status, review_status) VALUES
('recipe-116', '豆腐肉末蒸蛋', '豆腐、猪肉末与鸡蛋三合一，蛋白质极为丰富，口感嫩滑，是宝宝营养加餐的好选择。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '20分钟', '中级', '营养师精品', '陈营养师', 180, '三合一蛋白蒸蛋', 'published', 'approved'),
('recipe-117', '南瓜虾仁粥', '南瓜的甜味与虾仁的鲜味结合，颜色金黄，蛋白质丰富，是宝宝补锌的美味粥品。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '35分钟', '中级', '营养师精品', '陈营养师', 195, '金黄补锌粥', 'published', 'approved'),
('recipe-118', '胡萝卜鸡蛋饼', '胡萝卜丝与鸡蛋混合煎制，外酥内嫩，颜色橙黄，是宝宝早餐或加餐的好选择。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '18分钟', '初级', '营养师精品', '陈营养师', 330, '橙黄护眼早餐饼', 'published', 'approved'),
('recipe-119', '猪肉白菜软饭', '猪肉末与白菜搭配软饭，白菜富含维生素C，猪肉提供蛋白质，营养均衡，简单易做。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '28分钟', '初级', '营养师精品', '陈营养师', 155, '简单营养软饭', 'published', 'approved'),
('recipe-120', '三文鱼蔬菜粥', '三文鱼碎与多种蔬菜搭配熬粥，DHA丰富，营养全面，是宝宝补脑的营养粥品。', 'https://images.unsplash.com/photo-1467003909585-2f8a72700288?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '35分钟', '中级', '营养师精品', '陈营养师', 372, 'DHA补脑蔬菜粥', 'published', 'approved'),
('recipe-121', '玉米排骨汤面', '排骨熬制的浓汤搭配玉米和细面，钙质丰富，鲜味十足，是宝宝补钙的营养面食。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '55分钟', '高级', '营养师精品', '陈营养师', 175, '补钙鲜汤面', 'published', 'approved'),
('recipe-122', '西兰花鸡肉软饭', '西兰花与鸡肉搭配软饭，叶酸与蛋白质双补，颜色绿白相间，营养均衡。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '30分钟', '中级', '营养师精品', '陈营养师', 162, '叶酸蛋白双补饭', 'published', 'approved'),
('recipe-123', '香蕉鸡蛋松饼', '香蕉与鸡蛋制作的无面粉松饼，天然甜味，外酥内软，是宝宝健康零食的好选择。', 'https://images.unsplash.com/photo-1571771894821-ce9b6c11b08e?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '15分钟', '初级', '营养师精品', '陈营养师', 448, '无面粉健康松饼', 'published', 'approved'),
('recipe-124', '豆腐虾仁蒸蛋', '豆腐、虾仁与鸡蛋三合一，蛋白质极为丰富，口感嫩滑，是宝宝营养晚餐的好选择。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '20分钟', '中级', '营养师精品', '陈营养师', 192, '三合一嫩滑蒸蛋', 'published', 'approved'),
('recipe-125', '南瓜牛肉软饭', '南瓜的甜味与牛肉的鲜味结合，搭配软饭，铁质丰富，颜色金黄，是宝宝午餐的好选择。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '12-18月', 12, 18, '35分钟', '中级', '营养师精品', '陈营养师', 180, '金黄铁质午餐饭', 'published', 'approved')
INSERT INTO recipes (id, title, summary, cover_image, age_label, age_min_months, age_max_months, duration_label, difficulty_label, source, creator, favorites, review_focus, content_status, review_status) VALUES
('recipe-126', '番茄牛肉意面', '牛肉末与番茄酱搭配意大利面，是宝宝接触西式面食的好机会，营养丰富，口感丰富。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '30分钟', '中级', '营养师精品', '陈营养师', 405, '西式面食初体验', 'published', 'approved'),
('recipe-127', '鸡肉蔬菜炒饭', '鸡肉丁与多种蔬菜搭配炒饭，颜色丰富，营养全面，是宝宝学习使用勺子的好练习。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '25分钟', '中级', '营养师精品', '陈营养师', 255, '多彩营养炒饭', 'published', 'approved'),
('recipe-128', '三文鱼蔬菜饭团', '三文鱼碎与蔬菜混合捏成小饭团，DHA丰富，是宝宝外出携带的好零食，也是手指食物。', 'https://images.unsplash.com/photo-1467003909585-2f8a72700288?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '25分钟', '中级', '营养师精品', '陈营养师', 362, 'DHA手指食物饭团', 'published', 'approved'),
('recipe-129', '猪肉蔬菜馄饨', '薄皮馄饨包裹猪肉蔬菜馅，煮熟后皮薄馅嫩，是宝宝学习咀嚼的好练习。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '30分钟', '高级', '营养师精品', '陈营养师', 205, '皮薄馅嫩馄饨', 'published', 'approved'),
('recipe-130', '南瓜鸡蛋饼', '南瓜泥与鸡蛋混合煎制，外酥内嫩，颜色金黄，是宝宝早餐或加餐的好选择。', 'https://images.unsplash.com/photo-1506084868230-bb9d95c24759?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '18分钟', '初级', '营养师精品', '陈营养师', 340, '金黄早餐蛋饼', 'published', 'approved'),
('recipe-131', '虾仁炒蛋', '虾仁与鸡蛋同炒，蛋白质丰富，口感嫩滑，是宝宝补锌的快手美食。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '13分钟', '初级', '手机快速添加', '运营-小顾', 225, '快手补锌炒蛋', 'published', 'approved'),
('recipe-132', '牛肉蔬菜汤面', '牛肉片与多种蔬菜搭配面条，汤鲜味美，营养全面，是宝宝冬季暖胃的好选择。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '30分钟', '中级', '营养师精品', '陈营养师', 240, '冬季暖胃汤面', 'published', 'approved'),
('recipe-133', '香菇鸡肉饭', '香菇与鸡肉同炒后拌饭，鲜味十足，B族维生素丰富，是宝宝午餐的好选择。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '25分钟', '中级', '营养师精品', '陈营养师', 195, '鲜味B族维生素饭', 'published', 'approved'),
('recipe-134', '西兰花虾仁蒸蛋', '西兰花碎、虾仁与鸡蛋三合一蒸制，营养极为丰富，口感嫩滑，是宝宝营养晚餐。', 'https://images.unsplash.com/photo-1482049016688-2d3e1b311543?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '20分钟', '中级', '营养师精品', '陈营养师', 182, '三合一营养蒸蛋', 'published', 'approved'),
('recipe-135', '番茄鸡蛋炒饭', '经典番茄鸡蛋炒饭，酸甜开胃，颜色鲜艳，是宝宝最爱的炒饭之一，简单快手。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '15分钟', '初级', '营养师精品', '陈营养师', 435, '经典酸甜炒饭', 'published', 'approved')
INSERT INTO recipes (id, title, summary, cover_image, age_label, age_min_months, age_max_months, duration_label, difficulty_label, source, creator, favorites, review_focus, content_status, review_status) VALUES
('recipe-136', '猪肝洋葱炒饭', '猪肝与洋葱同炒后拌饭，铁质丰富，洋葱的甜味中和猪肝的腥味，每周1-2次。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '22分钟', '中级', '营养师精品', '陈营养师', 162, '高铁补血炒饭', 'published', 'approved'),
('recipe-137', '鳕鱼豆腐蒸蛋', '鳕鱼、豆腐与鸡蛋三合一，DHA与蛋白质极为丰富，口感嫩滑，是宝宝补脑的好选择。', 'https://images.unsplash.com/photo-1467003909585-2f8a72700288?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '20分钟', '中级', '营养师精品', '陈营养师', 205, 'DHA三合一蒸蛋', 'published', 'approved'),
('recipe-138', '胡萝卜牛肉饺子', '牛肉与胡萝卜馅料的饺子，铁质丰富，是宝宝学习咀嚼的好练习，也是家庭美食。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '40分钟', '高级', '营养师精品', '陈营养师', 180, '铁质丰富饺子', 'published', 'approved'),
('recipe-139', '南瓜小米饼', '南瓜泥与小米粉混合煎制，外酥内软，颜色金黄，是宝宝早餐或加餐的好选择。', 'https://images.unsplash.com/photo-1506084868230-bb9d95c24759?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '18分钟', '初级', '营养师精品', '陈营养师', 165, '金黄小米早餐饼', 'published', 'approved'),
('recipe-140', '鸡肉蔬菜包子', '鸡肉与蔬菜馅料的包子，皮薄馅嫩，是宝宝学习咀嚼的好练习，也是家庭早餐。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '50分钟', '高级', '营养师精品', '陈营养师', 155, '皮薄馅嫩早餐包', 'published', 'approved'),
('recipe-141', '三文鱼炒蛋', '三文鱼碎与鸡蛋同炒，DHA与蛋白质双补，口感嫩滑，是宝宝补脑的快手美食。', 'https://images.unsplash.com/photo-1467003909585-2f8a72700288?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '13分钟', '初级', '手机快速添加', '运营-小顾', 330, 'DHA快手炒蛋', 'published', 'approved'),
('recipe-142', '豆腐肉末炒饭', '豆腐碎与猪肉末搭配炒饭，蛋白质丰富，口感多样，是宝宝午餐的好选择。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '20分钟', '中级', '营养师精品', '陈营养师', 175, '双蛋白营养炒饭', 'published', 'approved'),
('recipe-143', '西红柿牛肉汤', '牛肉与西红柿同煮，汤色红润，铁质丰富，维生素C促进铁吸收，是宝宝补铁的好汤品。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '40分钟', '中级', '营养师精品', '陈营养师', 192, '红润补铁好汤', 'published', 'approved'),
('recipe-144', '香蕉燕麦饼', '香蕉与燕麦混合烤制，天然甜味，外酥内软，是宝宝健康零食的好选择，无需加糖。', 'https://images.unsplash.com/photo-1571771894821-ce9b6c11b08e?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '25分钟', '初级', '营养师精品', '陈营养师', 372, '无糖健康燕麦饼', 'published', 'approved'),
('recipe-145', '虾仁蔬菜炒饭', '虾仁与多种蔬菜搭配炒饭，颜色丰富，蛋白质丰富，是宝宝午餐的好选择。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '22分钟', '中级', '营养师精品', '陈营养师', 205, '多彩补锌炒饭', 'published', 'approved')
INSERT INTO recipes (id, title, summary, cover_image, age_label, age_min_months, age_max_months, duration_label, difficulty_label, source, creator, favorites, review_focus, content_status, review_status) VALUES
('recipe-146', '猪肉白菜饺子', '猪肉与白菜馅料的饺子，是中国传统美食，宝宝学习咀嚼的好练习，家庭团聚的好选择。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '40分钟', '高级', '营养师精品', '陈营养师', 185, '传统美食咀嚼练习', 'published', 'approved'),
('recipe-147', '南瓜鸡肉饭团', '南瓜泥与鸡肉碎混合捏成小饭团，颜色金黄，营养丰富，是宝宝外出携带的好零食。', 'https://images.unsplash.com/photo-1506084868230-bb9d95c24759?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '25分钟', '中级', '营养师精品', '陈营养师', 162, '金黄营养饭团', 'published', 'approved'),
('recipe-148', '鸡蛋蔬菜炒饭', '鸡蛋与多种蔬菜搭配炒饭，颜色丰富，营养全面，是宝宝最爱的炒饭之一。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '18分钟', '初级', '手机快速添加', '运营-小顾', 225, '多彩蔬菜炒饭', 'published', 'approved'),
('recipe-149', '牛肉蔬菜饺子', '牛肉与蔬菜馅料的饺子，铁质丰富，是宝宝学习咀嚼的好练习，营养均衡。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '40分钟', '高级', '营养师精品', '陈营养师', 172, '铁质均衡饺子', 'published', 'approved'),
('recipe-150', '香菇豆腐汤', '香菇与豆腐同煮，汤色清澈，鲜味十足，植物蛋白丰富，是宝宝清淡饮食的好选择。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '23分钟', '初级', '营养师精品', '陈营养师', 150, '清淡鲜味豆腐汤', 'published', 'approved'),
('recipe-151', '胡萝卜鸡蛋炒饭', '胡萝卜丁与鸡蛋搭配炒饭，颜色橙黄，护眼营养丰富，是宝宝午餐的好选择。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '18分钟', '初级', '营养师精品', '陈营养师', 175, '护眼橙黄炒饭', 'published', 'approved'),
('recipe-152', '鳕鱼蔬菜炒饭', '鳕鱼碎与蔬菜搭配炒饭，DHA丰富，营养全面，是宝宝补脑的美味主食。', 'https://images.unsplash.com/photo-1467003909585-2f8a72700288?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '22分钟', '中级', '营养师精品', '陈营养师', 192, 'DHA补脑炒饭', 'published', 'approved'),
('recipe-153', '西兰花牛肉饭', '西兰花与牛肉末搭配米饭，叶酸与铁质双补，颜色绿白相间，营养均衡。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '30分钟', '中级', '营养师精品', '陈营养师', 180, '叶酸铁质双补饭', 'published', 'approved'),
('recipe-154', '猪肉蔬菜炒饭', '猪肉末与多种蔬菜搭配炒饭，营养全面，是宝宝午餐的好选择，简单快手。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '20分钟', '初级', '手机快速添加', '运营-小顾', 165, '简单快手营养饭', 'published', 'approved'),
('recipe-155', '南瓜虾仁炒饭', '南瓜丁与虾仁搭配炒饭，颜色金黄，蛋白质丰富，是宝宝补锌的美味主食。', 'https://images.unsplash.com/photo-1506084868230-bb9d95c24759?auto=format&fit=crop&w=800&q=80', '19-24月', 19, 24, '22分钟', '中级', '营养师精品', '陈营养师', 185, '金黄补锌炒饭', 'published', 'approved')
INSERT INTO recipes (id, title, summary, cover_image, age_label, age_min_months, age_max_months, duration_label, difficulty_label, source, creator, favorites, review_focus, content_status, review_status) VALUES
('recipe-156', '番茄牛肉意大利面', '经典意大利面配番茄牛肉酱，是宝宝接触西式美食的好机会，营养丰富，口感丰富多样。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '24月+', 24, NULL, '35分钟', '中级', '营养师精品', '陈营养师', 425, '西式美食初体验', 'published', 'approved'),
('recipe-157', '鸡肉蔬菜炒面', '鸡肉丁与多种蔬菜搭配炒面，颜色丰富，营养全面，是宝宝学习使用筷子的好练习。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '24月+', 24, NULL, '25分钟', '中级', '营养师精品', '陈营养师', 240, '多彩营养炒面', 'published', 'approved'),
('recipe-158', '三文鱼寿司卷', '三文鱼与黄瓜、米饭卷成寿司，是宝宝接触日式美食的好机会，DHA丰富，颜色好看。', 'https://images.unsplash.com/photo-1467003909585-2f8a72700288?auto=format&fit=crop&w=800&q=80', '24月+', 24, NULL, '30分钟', '高级', '营养师精品', '陈营养师', 192, 'DHA日式美食', 'published', 'approved'),
('recipe-159', '猪肉蔬菜锅贴', '猪肉蔬菜馅料的锅贴，底部煎至金黄酥脆，是宝宝学习咀嚼的好练习，也是家庭美食。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '24月+', 24, NULL, '40分钟', '高级', '营养师精品', '陈营养师', 205, '金黄酥脆锅贴', 'published', 'approved'),
('recipe-160', '南瓜鸡肉咖喱饭', '温和咖喱搭配南瓜和鸡肉，颜色金黄，香气诱人，是宝宝接触香料的好机会（温和版）。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '24月+', 24, NULL, '35分钟', '中级', '营养师精品', '陈营养师', 372, '温和咖喱香料初体验', 'published', 'approved'),
('recipe-161', '虾仁蔬菜炒面', '虾仁与多种蔬菜搭配炒面，蛋白质丰富，颜色鲜艳，是宝宝午餐的好选择。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '24月+', 24, NULL, '25分钟', '中级', '营养师精品', '陈营养师', 215, '多彩补锌炒面', 'published', 'approved'),
('recipe-162', '牛肉蔬菜汉堡', '牛肉饼搭配蔬菜夹在软面包中，是宝宝接触西式快餐的健康版本，营养均衡。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '24月+', 24, NULL, '30分钟', '中级', '营养师精品', '陈营养师', 192, '健康西式汉堡', 'published', 'approved'),
('recipe-163', '香菇鸡肉炒面', '香菇与鸡肉搭配炒面，鲜味十足，B族维生素丰富，是宝宝午餐的好选择。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '24月+', 24, NULL, '25分钟', '中级', '营养师精品', '陈营养师', 180, '鲜味B族炒面', 'published', 'approved'),
('recipe-164', '西兰花虾仁炒饭', '西兰花与虾仁搭配炒饭，叶酸与蛋白质双补，颜色绿白相间，营养均衡。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '24月+', 24, NULL, '22分钟', '中级', '营养师精品', '陈营养师', 205, '叶酸蛋白双补饭', 'published', 'approved'),
('recipe-165', '番茄鸡蛋汤面', '经典番茄鸡蛋汤面，酸甜开胃，面条软烂，是宝宝最爱的面食之一，简单快手。', 'https://images.unsplash.com/photo-1547592180-85f173990554?auto=format&fit=crop&w=800&q=80', '24月+', 24, NULL, '20分钟', '初级', '营养师精品', '陈营养师', 448, '经典酸甜汤面', 'published', 'approved')
